import { resolvePath } from "@typespec/compiler";
import { createLinterRuleTester, createTester, expectDiagnostics, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { workerTypeSpecRule } from "./worker-type-spec.rule.js";

/**
 * A tester that includes @typespec/events so that @events unions compile correctly.
 */
const WorkerTester = createTester(resolvePath(import.meta.dirname, "../.."), {
  libraries: ["@a10n/blueprint-typespec", "@a10n/typespec-dbml", "@typespec/events"],
})
  .importLibraries()
  .using("State")
  .using("TypeSpec.Events");

// ── Shared snippet helpers ────────────────────────────────────────────────────

const INV = `
  @feature
  namespace Products.P.Features.F {
    @invariant(#{ predicate: "A task has an id.", why: "Reason." })
    op task_has_id(): void;
  }
`;

/** A minimal Store component with a seed model. */
const SEED_STORE = `
  @component(#{ type: ComponentType.Store })
  namespace Components.SeedStore {
    model Seed { id: string; }
  }
`;

/** A minimal Store with a RunRow model. */
const RUN_STORE = `
  @component(#{ type: ComponentType.Store })
  namespace Components.RunStore {
    model RunRow { id: string; }
  }
`;

// ── Tests ─────────────────────────────────────────────────────────────────────

describe("worker-type-spec rule", () => {
  let ruleTester: LinterRuleTester;
  let runner: Awaited<ReturnType<typeof WorkerTester.createInstance>>;

  beforeEach(async () => {
    runner = await WorkerTester.createInstance();
    ruleTester = createLinterRuleTester(runner, workerTypeSpecRule, "@a10n/blueprint-typespec");
  });

  // ── 1. worker-returns-void ────────────────────────────────────────────────

  describe("worker-returns-void", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_01
    it("T016_01: worker op returning void — no diagnostic", async () => {
      await ruleTester
        .expect(`
          ${INV}
          ${SEED_STORE}
          @events
          union LifecycleEvent {
            RunRequested: { id: string };
          }
          @component(#{ type: ComponentType.Service })
          @dependsOn([Components.SeedStore])
          namespace Components.OrchestratorService {
            @publishes(LifecycleEvent.RunRequested)
            @reads([Components.SeedStore.Seed])
            @operation(#{})
            op start_run(): void;

            @worker
            namespace Workers {
              @subscribes
              @reads([Components.SeedStore.Seed])
              op handle_run(event: LifecycleEvent.RunRequested): void;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_02
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_worker_type_spec:Products.A10nBlueprintEngine.Features.WorkerTypeSpec.worker_returns_void:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_no_orphan_invariant_layer:Products.A10nBlueprintEngine.Features.WorkerTypeSpec.worker_returns_void:must
    it("T016_02: worker op with non-void return — emits workerReturnsVoid", async () => {
      // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_worker_type_spec
      await ruleTester
        .expect(`
          ${INV}
          ${SEED_STORE}
          @events
          union LifecycleEvent {
            RunRequested: { id: string };
          }
          model RunResult { status: string; }
          @component(#{ type: ComponentType.Service })
          @dependsOn([Components.SeedStore])
          namespace Components.OrchestratorService {
            @publishes(LifecycleEvent.RunRequested)
            @reads([Components.SeedStore.Seed])
            @operation(#{})
            op start_run(): void;

            @worker
            namespace Workers {
              @subscribes
              @reads([Components.SeedStore.Seed])
              op handle_run(event: LifecycleEvent.RunRequested): RunResult;
            }
          }
        `)
        .toEmitDiagnostics([
          { code: "@a10n/blueprint-typespec/worker-type-spec", message: /handle_run.*returns non-void|non-void.*handle_run/ },
        ]);
    });
  });

  // ── 2. worker-has-subscription ────────────────────────────────────────────

  describe("worker-has-subscription", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_03
    it("T016_03: worker op with @subscribes — no diagnostic", async () => {
      await ruleTester
        .expect(`
          ${INV}
          ${SEED_STORE}
          @events
          union LifecycleEvent {
            RunRequested: { id: string };
          }
          @component(#{ type: ComponentType.Service })
          @dependsOn([Components.SeedStore])
          namespace Components.OrchestratorService {
            @publishes(LifecycleEvent.RunRequested)
            @reads([Components.SeedStore.Seed])
            @operation(#{})
            op start_run(): void;

            @worker
            namespace Workers {
              @subscribes
              @reads([Components.SeedStore.Seed])
              op handle_run(event: LifecycleEvent.RunRequested): void;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_04
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_worker_type_spec:Products.A10nBlueprintEngine.Features.WorkerTypeSpec.worker_has_subscription:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_no_orphan_invariant_layer:Products.A10nBlueprintEngine.Features.WorkerTypeSpec.worker_has_subscription:must
    it("T016_04: worker op without @subscribes — emits workerHasSubscription", async () => {
      // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_worker_type_spec
      await ruleTester
        .expect(`
          ${INV}
          ${SEED_STORE}
          @events
          union LifecycleEvent {
            RunRequested: { id: string };
          }
          @component(#{ type: ComponentType.Service })
          @dependsOn([Components.SeedStore])
          namespace Components.OrchestratorService {
            @publishes(LifecycleEvent.RunRequested)
            @reads([Components.SeedStore.Seed])
            @operation(#{})
            op start_run(): void;

            @worker
            namespace Workers {
              @reads([Components.SeedStore.Seed])
              op dead_handler(event: LifecycleEvent.RunRequested): void;
            }
          }
        `)
        .toEmitDiagnostics([
          { code: "@a10n/blueprint-typespec/worker-type-spec", message: /dead_handler.*no @subscribes|no @subscribes.*dead_handler/ },
        ]);
    });
  });

  // ── 3. worker-has-effect ──────────────────────────────────────────────────

  describe("worker-has-effect", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_05
    it("T016_05: worker op with @writes — no diagnostic", async () => {
      await ruleTester
        .expect(`
          ${INV}
          ${RUN_STORE}
          @events
          union LifecycleEvent {
            SomeEvent: { id: string };
          }
          @component(#{ type: ComponentType.Service })
          @dependsOn([Components.RunStore])
          namespace Components.TaskService {
            @publishes(LifecycleEvent.SomeEvent)
            @reads([Components.RunStore.RunRow])
            @operation(#{})
            op start_run(): void;

            @worker
            namespace Workers {
              @subscribes
              @writes([Components.RunStore.RunRow])
              op handle_event(event: LifecycleEvent.SomeEvent): void;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_06
    it("T016_06: worker op with @calls — no diagnostic", async () => {
      await ruleTester
        .expect(`
          ${INV}
          @events
          union LifecycleEvent {
            SomeEvent: { id: string };
          }
          @component(#{ type: ComponentType.Sdk })
          namespace Components.OtherSdk {
            @operation(#{})
            op handle(): void;
          }
          @component(#{ type: ComponentType.Service })
          @dependsOn([Components.OtherSdk])
          namespace Components.TaskService {
            namespace Http {
              @publishes(LifecycleEvent.SomeEvent)
              @calls([Components.OtherSdk.handle])
              op start_run(): void;
            }

            @worker
            namespace Workers {
              @subscribes
              @calls([Components.OtherSdk.handle])
              op handle_event(event: LifecycleEvent.SomeEvent): void;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_07
    it("T016_07: worker op with @reads — no diagnostic", async () => {
      await ruleTester
        .expect(`
          ${INV}
          ${SEED_STORE}
          @events
          union LifecycleEvent {
            SomeEvent: { id: string };
          }
          @component(#{ type: ComponentType.Service })
          @dependsOn([Components.SeedStore])
          namespace Components.TaskService {
            @publishes(LifecycleEvent.SomeEvent)
            @reads([Components.SeedStore.Seed])
            @operation(#{})
            op start_run(): void;

            @worker
            namespace Workers {
              @subscribes
              @reads([Components.SeedStore.Seed])
              op handle_event(event: LifecycleEvent.SomeEvent): void;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_08
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_worker_type_spec:Products.A10nBlueprintEngine.Features.WorkerTypeSpec.worker_has_effect:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_no_orphan_invariant_layer:Products.A10nBlueprintEngine.Features.WorkerTypeSpec.worker_has_effect:must
    it("T016_08: worker op with no @reads/@writes/@calls — emits workerHasEffect", async () => {
      // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_worker_type_spec
      await ruleTester
        .expect(`
          ${INV}
          @events
          union LifecycleEvent {
            SomeEvent: { id: string };
          }
          @component(#{ type: ComponentType.Service })
          namespace Components.TaskService {
            @publishes(LifecycleEvent.SomeEvent)
            @operation(#{})
            op start_run(): void;

            @worker
            namespace Workers {
              @subscribes
              op idle_handler(event: LifecycleEvent.SomeEvent): void;
            }
          }
        `)
        .toEmitDiagnostics([
          { code: "@a10n/blueprint-typespec/worker-type-spec", message: /idle_handler.*no @reads|no-op handler/ },
        ]);
    });
  });

  // ── 4. subscribes-live-event ──────────────────────────────────────────────

  describe("subscribes-live-event", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_09
    it("T016_09: worker subscribes to event published by an op — no diagnostic", async () => {
      await ruleTester
        .expect(`
          ${INV}
          ${SEED_STORE}
          @events
          union LifecycleEvent {
            RunRequested: { id: string };
          }
          @component(#{ type: ComponentType.Service })
          @dependsOn([Components.SeedStore])
          namespace Components.OrchestratorService {
            @publishes(LifecycleEvent.RunRequested)
            @reads([Components.SeedStore.Seed])
            @operation(#{})
            op start_run(): void;

            @worker
            namespace Workers {
              @subscribes
              @reads([Components.SeedStore.Seed])
              op init_run(event: LifecycleEvent.RunRequested): void;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_10
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_worker_type_spec:Products.A10nBlueprintEngine.Features.WorkerTypeSpec.subscribes_live_event:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_no_orphan_invariant_layer:Products.A10nBlueprintEngine.Features.WorkerTypeSpec.subscribes_live_event:must
    it("T016_10: worker subscribes to event nobody publishes — emits subscribesLiveEvent", async () => {
      // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_worker_type_spec
      await ruleTester
        .expect(`
          ${INV}
          ${SEED_STORE}
          model RunRequestedData { id: string; }
          model OrphanEventData { id: string; }
          @events
          union LifecycleEvent {
            RunRequested: RunRequestedData;
            OrphanEvent: OrphanEventData;
          }
          @component(#{ type: ComponentType.Service })
          @dependsOn([Components.SeedStore])
          namespace Components.OrchestratorService {
            @publishes(LifecycleEvent.RunRequested)
            @reads([Components.SeedStore.Seed])
            @operation(#{})
            op start_run(): void;

            @worker
            namespace Workers {
              @subscribes
              @reads([Components.SeedStore.Seed])
              op dead_worker(event: LifecycleEvent.OrphanEvent): void;
            }
          }
        `)
        .toEmitDiagnostics([
          { code: "@a10n/blueprint-typespec/worker-type-spec", message: /dead_worker.*OrphanEvent|OrphanEvent.*never fire|subscription will never/ },
        ]);
    });
  });

  // ── 5. subscribes-op-only ─────────────────────────────────────────────────

  describe("subscribes-op-only", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_11
    it("T016_11: @subscribes on a worker op — no diagnostic", async () => {
      await ruleTester
        .expect(`
          ${INV}
          ${SEED_STORE}
          @events
          union LifecycleEvent {
            SomeEvent: { id: string };
          }
          @component(#{ type: ComponentType.Service })
          @dependsOn([Components.SeedStore])
          namespace Components.TaskService {
            @publishes(LifecycleEvent.SomeEvent)
            @reads([Components.SeedStore.Seed])
            @operation(#{})
            op start(): void;

            @worker
            namespace Workers {
              @subscribes
              @reads([Components.SeedStore.Seed])
              op handle(event: LifecycleEvent.SomeEvent): void;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_12
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_worker_type_spec:Products.A10nBlueprintEngine.Features.WorkerTypeSpec.subscribes_op_only:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_no_orphan_invariant_layer:Products.A10nBlueprintEngine.Features.WorkerTypeSpec.subscribes_op_only:must
    it("T016_12: @subscribes on a non-worker op — emits subscribesOpOnly", async () => {
      // The decorator fires a compiler-level warning (not a linter-rule diagnostic),
      // so we diagnose via the runner directly instead of the rule tester.
      // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_worker_type_spec
      const [, diagnostics] = await runner.compileAndDiagnose(`
          ${INV}
          ${SEED_STORE}
          @events
          union LifecycleEvent {
            SomeEvent: { id: string };
          }
          @component(#{ type: ComponentType.Service })
          @dependsOn([Components.SeedStore])
          namespace Components.TaskService {
            @subscribes
            @reads([Components.SeedStore.Seed])
            @operation(#{})
            op handle_request(event: LifecycleEvent.SomeEvent): void;
          }
        `);
      expectDiagnostics(diagnostics, [
        { code: "@a10n/blueprint-typespec/subscribes-op-only", message: /@subscribes can only appear.*@worker|outside a @worker namespace/ },
      ]);
    });
  });
});
